defaultValue.value:
({
    className,
    open = false,
    invisible = false,
    timeout = 200,
    children,
    onClose,
    dataTestId,
    transitionClassNames = styles,
    transparent = false,
    ...restProps
}) => {
    const nodeRef = useRef(null);

    return (
        <CSSTransition
            timeout={timeout}
            unmountOnExit={true}
            classNames={transitionClassNames}
            in={!invisible && open}
            appear={true}
            {...restProps}
            nodeRef={nodeRef}
        >
            <div
                ref={nodeRef}
                aria-hidden={true}
                onClick={onClose}
                data-test-id={dataTestId}
                className={cn(styles.backdrop, className, {
                    [styles.transparent]: transparent,
                })}
            >
                {children}
            </div>
        </CSSTransition>
    );
}

